/**
* Compress the hash description using a Huffman coding.
*
* @param d the data
* @return the compressed data
*/
    private static byte[] compress(byte[] d) {
        Deflater deflater = new Deflater();
        deflater.setStrategy(Deflater.HUFFMAN_ONLY);
