        MVMap<int[], Boolean> keepSegment = storeTemp.openMap("keep");
        while (list.size() > 0) {
            list.sort((o1, o2) -> {
                int[] k1 = o1.getKey();
                int[] k2 = o2.getKey();
                int comp = 0;
                for (int i = 0; i < k1.length - 1; i++) {
                long x1 = k1[i];
                long x2 = k2[i];
                if (x1 > x2) {
                    comp = 1;
                    break;
                } else if (x1 < x2) {
                    comp = -1;
                    break;
                }
                }
                return comp;
            });
